import { Toolbar as ToolbarPrimitive } from '@base-ui/react/toolbar';
import { clsx } from 'clsx';
import { useMemo, type ComponentProps } from 'react';
import { ChevronLeftIcon, ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Pagination.module.css';

function clampPage(page: number, count: number) {
  return Math.min(Math.max(page, 1), count);
}

function range(start: number, end: number) {
  return Array.from({ length: end - start + 1 }, (_, index) => start + index);
}

function usePagination({
  count,
  page,
  siblingCount = 1,
  boundaryCount = 1,
}: {
  count: number;
  page: number;
  siblingCount?: number;
  boundaryCount?: number;
}) {
  const safeCount = Math.max(0, Math.floor(count));
  const safePage = safeCount === 0 ? 0 : clampPage(Math.floor(page), safeCount);
  const safeSiblingCount = Math.max(0, Math.floor(siblingCount));
  const safeBoundaryCount = Math.max(0, Math.floor(boundaryCount));

  const items = useMemo(() => {
    if (safeCount === 0) {
      return [];
    }

    const totalPageNumbers = safeSiblingCount * 2 + 3 + safeBoundaryCount * 2;

    if (safeCount <= totalPageNumbers) {
      return range(1, safeCount);
    }

    const startPages = range(1, safeBoundaryCount);
    const endPages = range(safeCount - safeBoundaryCount + 1, safeCount);

    const siblingsStart = Math.max(
      Math.min(
        safePage - safeSiblingCount,
        safeCount - safeBoundaryCount - safeSiblingCount * 2 - 1,
      ),
      safeBoundaryCount + 2,
    );

    const siblingsEnd = Math.min(
      Math.max(safePage + safeSiblingCount, safeBoundaryCount + safeSiblingCount * 2 + 2),
      endPages[0] - 2,
    );

    return [
      ...startPages,
      ...(siblingsStart > safeBoundaryCount + 2
        ? ['ellipsis-start' as const]
        : safeBoundaryCount + 1 < safeCount - safeBoundaryCount
          ? [safeBoundaryCount + 1]
          : []),
      ...range(siblingsStart, siblingsEnd),
      ...(siblingsEnd < safeCount - safeBoundaryCount - 1
        ? ['ellipsis-end' as const]
        : safeCount - safeBoundaryCount > safeBoundaryCount
          ? [safeCount - safeBoundaryCount]
          : []),
      ...endPages,
    ];
  }, [safeBoundaryCount, safeCount, safePage, safeSiblingCount]);

  return {
    items,
    page: safePage,
    canNextPage: safeCount > 0 && safePage < safeCount,
    canPreviousPage: safePage > 1,
    nextPage: safeCount === 0 ? 0 : Math.min(safePage + 1, safeCount),
    previousPage: safePage <= 1 ? safePage : safePage - 1,
  };
}

const getPaginationRender = ({ href }: ToolbarPrimitive.Link.Props) => {
  if (href != null) {
    return undefined;
  }

  return <button type="button" />;
};

function Pagination({
  'aria-label': ariaLabel = 'Pagination',
  className,
  ...props
}: ComponentProps<'nav'>) {
  return (
    <nav
      data-slot="pagination-root"
      aria-label={ariaLabel}
      className={clsx(styles.root, className)}
      {...props}
    />
  );
}

function PaginationContent({ className, ...props }: ToolbarPrimitive.Root.Props) {
  return (
    <ToolbarPrimitive.Root
      data-slot="pagination-content"
      className={mergeClassName(className, styles.content)}
      {...props}
    />
  );
}

function PaginationItem({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="pagination-item" className={clsx(styles.item, className)} {...props} />;
}

function PaginationLink({
  className,
  isActive,
  render,
  ...props
}: ToolbarPrimitive.Link.Props & {
  isActive?: boolean;
}) {
  return (
    <ToolbarPrimitive.Link
      data-slot="pagination-link"
      aria-current={isActive ? 'page' : undefined}
      className={mergeClassName(className, styles.link, isActive && styles.linkActive)}
      render={render ?? getPaginationRender(props)}
      {...props}
    />
  );
}

function PaginationPrevious({
  children,
  className,
  render,
  'aria-label': ariaLabel,
  ...props
}: ToolbarPrimitive.Link.Props) {
  return (
    <PaginationLink
      aria-label={children ? ariaLabel : (ariaLabel ?? 'Go to previous page')}
      className={mergeClassName(className, styles.previous, !children && styles.iconOnly)}
      render={render}
      {...props}
    >
      {children ?? <ChevronLeftIcon />}
    </PaginationLink>
  );
}

function PaginationNext({
  children,
  className,
  render,
  'aria-label': ariaLabel,
  ...props
}: ToolbarPrimitive.Link.Props) {
  return (
    <PaginationLink
      aria-label={children ? ariaLabel : (ariaLabel ?? 'Go to next page')}
      className={mergeClassName(className, styles.next, !children && styles.iconOnly)}
      render={render}
      {...props}
    >
      {children ?? <ChevronRightIcon />}
    </PaginationLink>
  );
}

function PaginationEllipsis({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span data-slot="pagination-ellipsis" className={clsx(styles.ellipsis, className)} {...props}>
      <span aria-hidden>...</span>
      <span className={styles.visuallyHidden}>More pages</span>
    </span>
  );
}

export {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationPrevious,
  PaginationNext,
  PaginationEllipsis,
  usePagination,
};

@layer ui.components {
  .root {
    display: flex;
  }

  .content {
    display: inline-flex;
    align-items: center;
    gap: var(--pagination-gap, var(--spacing-1));
  }

  .item {
    display: inline-flex;
  }

  .link,
  .ellipsis {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: var(--pagination-item-size, var(--size-lg));
    min-height: var(--pagination-item-size, var(--size-lg));
    border-radius: var(--pagination-item-radius, var(--radius-md));
    font-size: var(--pagination-font-size, var(--text-sm));
    font-weight: var(--pagination-font-weight, var(--weight-medium));
    line-height: var(--pagination-line-height, var(--line-height-text-sm));
  }

  .link {
    gap: var(--spacing-2);
    border: var(--border-width-sm) solid var(--pagination-item-border-color, var(--color-border));
    padding-inline: var(--pagination-item-padding-inline, 0.75rem);
    background-color: var(--pagination-item-bg, var(--color-background));
    color: var(--pagination-item-color, var(--color-foreground));
    text-decoration: none;
    user-select: none;
    white-space: nowrap;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default),
      opacity var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--pagination-item-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(--border-width-md) solid var(--color-ring);
      outline-offset: -1px;
    }

    &[aria-disabled='true'],
    &[data-disabled],
    &[disabled] {
      opacity: var(--pagination-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }

    :where(svg) {
      flex-shrink: 0;
      width: var(--pagination-icon-size, 1rem);
      height: var(--pagination-icon-size, 1rem);
    }
  }

  .linkActive,
  .link[aria-current='page'] {
    border-color: var(--pagination-item-border-color-active, var(--color-foreground));
    background-color: var(--pagination-item-bg-active, var(--color-foreground));
    color: var(--pagination-item-color-active, var(--color-background));

    @media (hover: hover) {
      &:hover {
        background-color: var(--pagination-item-bg-active, var(--color-foreground));
      }
    }
  }

  .previous,
  .next {
    padding-inline: max(var(--pagination-item-padding-inline, 0.75rem), var(--spacing-3));
  }

  .iconOnly {
    width: var(--pagination-item-size, var(--size-lg));
    padding-inline: 0;
  }

  .ellipsis {
    color: var(--pagination-ellipsis-color, var(--color-muted-foreground));
    user-select: none;
  }

  .visuallyHidden {
    position: absolute;
    width: 1px;
    height: 1px;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    white-space: nowrap;
    border: 0;
    padding: 0;
  }
}

export {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationPrevious,
  PaginationNext,
  PaginationEllipsis,
  usePagination,
} from './Pagination';
